package com.cho2hand.marketplace.service.impl.admin; import com.cho2hand.marketplace.dto.report.AdminReportResponse;import com.cho2hand.marketplace.dto.report.AdminStatsResponse;import com.cho2hand.marketplace.exception.ListingNotFoundException;import com.cho2hand.marketplace.repository.listing.ListingRepository;import com.cho2hand.marketplace.repository.report.ListingReportRepository;import com.cho2hand.marketplace.repository.user.UserRepository;import com.cho2hand.marketplace.service.admin.AdminService;import java.time.*;import java.util.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service @Transactional public class AdminServiceImpl implements AdminService{private static final long ACTIVE_STATUS_ID=1L;private static final ZoneId HO_CHI_MINH=ZoneId.of("Asia/Ho_Chi_Minh");private final ListingReportRepository reports;private final ListingRepository listings;private final UserRepository users;public AdminServiceImpl(ListingReportRepository r,ListingRepository l,UserRepository u){reports=r;listings=l;users=u;}@Transactional(readOnly=true) public AdminStatsResponse stats(){var start=LocalDate.now(HO_CHI_MINH).atStartOfDay(HO_CHI_MINH).toInstant();return new AdminStatsResponse(users.count(),listings.count(),listings.countByListingStatusIdAndArchivedAtIsNull(ACTIVE_STATUS_ID),listings.countByArchivedAtIsNotNull(),listings.countByPublishedAtGreaterThanEqualAndArchivedAtIsNull(start),reports.count(),reports.countByStatus("OPEN"));}@Transactional(readOnly=true) public List<AdminReportResponse> reports(){return reports.findAllByOrderByCreatedAtDesc().stream().map(r->new AdminReportResponse(r.getId(),r.getListingId(),r.getReporterUserId(),r.getReasonId(),r.getDetails(),r.getStatus(),r.getResolutionNote(),r.getResolvedAt(),r.getCreatedAt())).toList();}public void archive(Long id){listings.findById(id).orElseThrow(()->new ListingNotFoundException(id)).setArchivedAt(Instant.now());}public void resolve(Long admin,Long reportId,boolean archive){var report=reports.findById(reportId).orElseThrow(()->new com.cho2hand.marketplace.exception.LookupValueNotFoundException("Report",reportId.toString()));if(archive)archive(report.getListingId());report.resolve(archive?"ARCHIVED":"DISMISSED",null,admin);}}
